def _existing_voice_file(dataset_dir: Path) -> Path | None:
    """Return the single voice clip in `<dataset_dir>/voice.*` if present.
    Only the file's stem matters — extension picks among TRAIN_VOICE_EXTS."""
    if not dataset_dir.is_dir():
        return None
    for ext in TRAIN_VOICE_EXTS:
        candidate = dataset_dir / f"voice{ext}"
        if candidate.is_file():
            return candidate
    return None

# Counter for new training-job ids — short, sortable, unique-per-day.
_TRAIN_COUNTER = 0
_TRAIN_COUNTER_LOCK = threading.Lock()


def _new_train_job_id() -> str:
    """Return a short identifier like `trn-20260510-1430-a3` — sortable,
    human-scannable, unique per panel run (the suffix counter avoids
    collisions within the same minute)."""
    global _TRAIN_COUNTER
    with _TRAIN_COUNTER_LOCK:
        _TRAIN_COUNTER += 1
        n = _TRAIN_COUNTER
    ts = time.strftime("%Y%m%d-%H%M")
    suffix = base36 = ""
    # Two-char base36 to keep the id terse; rolls over after ~1300 calls.
    _v = n
    alpha = "0123456789abcdefghijklmnopqrstuvwxyz"
    while _v > 0 and len(base36) < 3:
        base36 = alpha[_v % 36] + base36
        _v //= 36
    suffix = (base36 or "0").rjust(2, "0")
    return f"trn-{ts}-{suffix}"


def _train_dataset_dir(job_id: str) -> Path:
    """Per-job dataset folder. Holds images/, captions/, spec.json."""
    p = TRAIN_DIR / job_id
    return p


def _safe_job_id(job_id: str) -> str:
    """Reject anything that isn't `^[A-Za-z0-9_-]+$`. Prevents
    path-traversal via crafted job_id form values."""
    if not job_id or not re.fullmatch(r"[A-Za-z0-9_\-]+", job_id):
        raise ValueError(f"invalid job_id: {job_id!r}")
    if len(job_id) > 64:
        raise ValueError("job_id too long")
    return job_id


def _normalise_caption_text(text: str, trigger: str | None = None) -> str:
    """Coerce a caption body into LTX format:
        [VISUAL]: <trigger>, <description>
        [TEXT]: <on-screen text or None>

    Forgiving on input shape:
      * Strips BOM + CRLF.
      * If the first non-empty line lacks `[VISUAL]:` and a trigger is known,
        prepend `[VISUAL]: <trigger>, ` — only when the line doesn't already
        start with the trigger (avoid double-trigger).
      * If `[TEXT]:` is missing entirely, append `[TEXT]: None`.

    Does not enforce content rules — the UI surfaces a soft warning when the
    caption is < 10 words. Returns a normalised string ready to write to disk.
    """
    if not text:
        return ""
    # Strip UTF-8 BOM + normalise line endings.
    text = text.lstrip("﻿").replace("\r\n", "\n").replace("\r", "\n").strip()

    # Auto-prepend [VISUAL]: when missing. Match case-insensitive at the
    # very start of the first non-empty line.
    if not re.match(r"^\s*\[VISUAL\]\s*:", text, re.IGNORECASE):
        prefix = "[VISUAL]: "
        first_line = text.split("\n", 1)[0].strip()
        if trigger and first_line.lower().startswith(trigger.lower()):
            # Line already starts with trigger — just add the [VISUAL]: tag.
            text = prefix + text
        elif trigger:
            # No trigger yet; add `[VISUAL]: <trigger>, ` so the trainer sees a
            # token at position 0 of the [VISUAL]: body.
            text = f"{prefix}{trigger}, {text}"
        else:
            text = prefix + text

    # Auto-append [TEXT]: None if absent.
    if not re.search(r"^\s*\[TEXT\]\s*:", text, re.IGNORECASE | re.MULTILINE):
        text = text.rstrip() + "\n[TEXT]: None"
    return text + ("\n" if not text.endswith("\n") else "")


def _decode_caption_bytes(data: bytes) -> str:
    """Best-effort UTF-8 decode; fall back to latin-1 for legacy Win-1252
    captions. Strip nothing — `_normalise_caption_text` handles cleanup."""
    try:
        return data.decode("utf-8")
    except UnicodeDecodeError:
        return data.decode("latin-1", errors="replace")


def _caption_word_count(text: str) -> int:
    """Cheap word count for the < 10 words warning. Excludes the `[VISUAL]:` /
    `[TEXT]:` tag tokens so a sparse `[VISUAL]: bizarrotrn, man` doesn't read
    as 4 words and slip past the threshold."""
    body = re.sub(r"\[(?:VISUAL|TEXT)\]\s*:", " ", text, flags=re.IGNORECASE)
    return len([w for w in re.split(r"\s+", body.strip()) if w])


# ---------- Caption ↔ Image pairing helpers ----------------------------------
# Each training dataset records a `caption_map.json` next to images/ + captions/
# that maps the user's original filename stem (e.g. `image_001`) to the
# panel-renumbered saved stem (e.g. `char_001`). This lets a user upload
# `image_001.png` + `image_001.txt` in any order and have them pair correctly.

_TRAIN_CAPTION_MAP_NAME = "caption_map.json"


def _train_caption_map_path(dataset_dir: Path) -> Path:
    return dataset_dir / _TRAIN_CAPTION_MAP_NAME


def _train_read_caption_map(dataset_dir: Path) -> dict[str, str]:
    p = _train_caption_map_path(dataset_dir)
    if not p.is_file():
        return {}
    try:
        data = json.loads(p.read_text(encoding="utf-8"))
        if isinstance(data, dict):
            return {str(k): str(v) for k, v in data.items()
                    if isinstance(k, str) and isinstance(v, str)}
    except (OSError, json.JSONDecodeError):
        pass
    return {}


def _train_write_caption_map(dataset_dir: Path, mapping: dict[str, str]) -> None:
    p = _train_caption_map_path(dataset_dir)
    try:
        p.write_text(json.dumps(mapping, indent=2), encoding="utf-8")
    except OSError:
        pass


def _train_set_caption_map_entry(dataset_dir: Path,
                                 original_stem: str,
                                 saved_stem: str) -> None:
    m = _train_read_caption_map(dataset_dir)
    m[original_stem] = saved_stem
    _train_write_caption_map(dataset_dir, m)


def _train_reconcile_one(dataset_dir: Path,
                         original_stem: str,
                         saved_stem: str) -> bool:
    """If a caption file exists under `original_stem.txt`, rename it to
    `saved_stem.txt`. Used when the user uploads `image_001.txt` BEFORE its
    matching `image_001.png` arrives. Returns True if a paired caption now
    sits under `<captions>/<saved_stem>.txt`."""
    captions_dir = dataset_dir / "captions"
    saved_path = captions_dir / f"{saved_stem}.txt"
    if saved_path.is_file():
        return True
    if original_stem == saved_stem:
        return False
    parked = captions_dir / f"{original_stem}.txt"
    if parked.is_file():
        try:
            parked.rename(saved_path)
            return True
        except OSError:
            return False
    return False


def _train_reconcile_captions(dataset_dir: Path) -> tuple[int, int, list[str]]:
    """Called on training start. Walks images/ + captions/, ensures every
    caption under an *original* stem in caption_map.json is moved to its
    saved stem so the trainer's per-image lookup hits. Returns
    (paired_count, total_images, warnings)."""
    images_dir = dataset_dir / "images"
    captions_dir = dataset_dir / "captions"
    cmap = _train_read_caption_map(dataset_dir)
    if not images_dir.is_dir():
        return 0, 0, ["images dir missing"]
    images = [p for p in sorted(images_dir.iterdir())
              if p.is_file() and p.suffix.lower() in TRAIN_IMAGE_EXTS]
    total = len(images)
    warnings: list[str] = []
    if not captions_dir.is_dir():
        return 0, total, warnings
    for original, saved in cmap.items():
        if original == saved:
            continue
        parked = captions_dir / f"{original}.txt"
        target = captions_dir / f"{saved}.txt"
        if parked.is_file() and not target.is_file():
            try:
                parked.rename(target)
            except OSError as e:
                warnings.append(f"could not move {parked.name} → {target.name}: {e}")
    paired = sum(1 for img in images
                 if (captions_dir / f"{img.stem}.txt").is_file())
    return paired, total, warnings


def _suggest_trigger_token() -> str:
    """Generate a rare token of the form `<3-letter><2-digit>` (e.g. `mrz07`,
    `lqx42`). Avoids English-word collisions by picking three consonants for
    the leading run — phonotactically rare in English, almost always unique
    across the LTX vocabulary's text encoder. The two-digit tail prevents
    accidental clashes with existing LoRA triggers a user already has
    installed (e.g. an `mrz` LoRA + an `mrz07` LoRA coexist fine)."""
    # Skip vowels + ambiguous letters (l, i, o → 1, 0). Keep the set rare-in-
    # English (no common bigrams like 'th', 'st', 'sh').
    consonants = "bcdfghjkmnpqrstvwxyz"
    while True:
        letters = "".join(random.choice(consonants) for _ in range(3))
        # Reject anything that happens to spell a common letter pattern.
        if letters in ("the", "and", "for", "but"):
            continue
        digits = f"{random.randint(0, 99):02d}"
        return letters + digits


def _train_estimate_seconds(preset: str, image_count: int, *,
                            steps_override: int | None = None,
                            is_style: bool = False) -> int:
    """Wall-time estimate in seconds for a training run. The image count
    has a small overhead for the preprocess pass (image → VAE latent
    cache, ~3 s/image on M4 Max), then `steps * seconds_per_step` for
    the train loop itself.

    `is_style` switches the preset lookup table — style training pulls
    its seconds_per_step from TRAIN_STYLE_PRESETS, not TRAIN_PRESETS."""
    table = TRAIN_STYLE_PRESETS if is_style else TRAIN_PRESETS
    cfg = table.get(preset) or table["quick"]
    steps = steps_override if steps_override else cfg["steps"]
    preprocess = 3.0 * max(0, image_count)
    train = float(steps) * float(cfg["seconds_per_step"])
    return int(preprocess + train + 30)  # +30 s for setup + checkpoint write


def _train_list_completed() -> list[dict]:
    """Scan mlx_models/loras/ for .safetensors with a Phosphene-trained
    sidecar (`kind=train_character` OR `kind=train_style`) and return one
    record per discovered run for the Trained-LoRAs list in the Train tab.
    Surfacing both kinds in a single list lets the user see their full
    training inventory in one place; the UI filters by `train_type` to show
    the kind that matches the active train-type toggle (and lists everything
    when "All" is selected)."""
    out: list[dict] = []
    if LORAS_DIR.exists():
        for p in sorted(LORAS_DIR.iterdir(),
                        key=lambda x: x.stat().st_mtime if x.exists() else 0,
                        reverse=True):
            if p.suffix.lower() != ".safetensors":
                continue
            # Style LoRAs use a `.style.safetensors` suffix, so the sidecar
            # is `.style.json` not `.json`. Probe both paths.
            sidecar_candidates = [p.with_suffix(".json")]
            if p.name.endswith(".style.safetensors"):
                sidecar_candidates.insert(
                    0, p.with_name(p.name[: -len(".safetensors")] + ".json")
                )
            sidecar = next((s for s in sidecar_candidates if s.is_file()), None)
            if sidecar is None:
                continue
            try:
                meta = json.loads(sidecar.read_text(encoding="utf-8"))
            except Exception:
                continue
            kind = meta.get("kind")
            if kind not in ("train_character", "train_style"):
                continue
            try:
                stat = p.stat()
            except OSError:
                continue
            out.append({
                "id": meta.get("job_id") or p.stem,
                "name": meta.get("name") or p.stem,
                "trigger": meta.get("trigger") or "",
                "preset": meta.get("preset") or "",
                "kind": kind,
                "train_type": meta.get("train_type")
                                or ("style" if kind == "train_style"
                                    else "character"),
                "path": str(p),
                "filename": p.name,
                "size_mb": round(stat.st_size / (1024 * 1024), 1),
                "created_at": meta.get("created_at") or stat.st_mtime,
                "image_count": meta.get("image_count") or 0,
            })
    return out


def _train_required_models() -> list[dict]:
    """Return the list of model files Train Character needs and whether each
    is present locally. Surfaces missing models to the UI so the user can
    one-click download them via the existing hf flow.

    Train Character requires `transformer-dev.safetensors` from the LTX-2.3
    Q4 repo (the dev base — distilled is structurally wrong for training:
    different sigma schedule than the trainer's flow-matching objective).
    The default install ships distilled but NOT dev to save ~11 GB on disk
    for users who only run inference.

    Gemma + the rest of the Q4 stack (vae, audio, etc.) are already required
    for inference so they should already be present, but we check anyway.
    """
    q4_local_dir = ROOT / "mlx_models" / "ltx-2.3-mlx-q4"
    q4_repo_id = "dgrauet/ltx-2.3-mlx-q4"
    gemma_local_dir = ROOT / "mlx_models" / "gemma-3-12b-it-4bit"
    gemma_repo_id = "mlx-community/gemma-3-12b-it-4bit"

    def _file_present(local_dir: Path, repo_id: str, filename: str) -> bool:
        p = local_dir / filename
        try:
            if p.exists() and p.stat().st_size >= _MIN_FILE_BYTES:
                return True
        except OSError:
            pass
        cache_dir = _repo_hf_cache_dir(repo_id)
        if cache_dir is not None:
            cp = cache_dir / filename
            try:
                if cp.exists() and cp.stat().st_size >= _MIN_FILE_BYTES:
                    return True
            except OSError:
                pass
        return False

    items = [
        {
            "key": "ltx_dev_transformer",
            "label": "LTX-2.3 dev transformer (training-only)",
            "blurb": "Required for training. Standard inference uses the distilled "
                     "transformer instead; the dev transformer has the right "
                     "flow-matching schedule for LoRA-from-images training.",
            "repo_id": q4_repo_id,
            "filename": "transformer-dev.safetensors",
            "local_dir": str(q4_local_dir),
            "size_gb": 11.0,
            "ready": _file_present(q4_local_dir, q4_repo_id,
                                   "transformer-dev.safetensors"),
        },
        {
            "key": "gemma_text_encoder",
            "label": "Gemma 3 12B (text encoder)",
            "blurb": "Encodes prompts for both inference and training. Already "
                     "required by Phosphene's renderer, so this is usually green.",
            "repo_id": gemma_repo_id,
            "filename": "config.json",
            "local_dir": str(gemma_local_dir),
            "size_gb": 6.0,
            "ready": _file_present(gemma_local_dir, gemma_repo_id, "config.json"),
        },
    ]
    return items


def _train_install_dev_transformer(push_log) -> dict:
    """Trigger an hf download for just `transformer-dev.safetensors` from
    the LTX-2.3 Q4 repo. Reuses the same `hf download` binary the existing
    HF download flow uses; runs synchronously in a worker thread so the
    caller can stream progress (the panel currently invokes this from a
    /train/install endpoint that returns quickly + then polls /status).

    Returns {"ok": True, "started": True, "repo_id": ...} or {"ok": False,
    "error": "..."} if the download couldn't be started (already running,
    binary missing, etc.).
    """
    import subprocess
    if DOWNLOAD["active"]:
        return {"ok": False,
                "error": f"another download is already active "
                         f"({DOWNLOAD.get('repo_id', '?')})."}

    repo_id = "dgrauet/ltx-2.3-mlx-q4"
    local_dir = ROOT / "mlx_models" / "ltx-2.3-mlx-q4"
    local_dir.mkdir(parents=True, exist_ok=True)

    hf_bin = HF_BIN if HF_BIN is not None else _resolve_hf()
    if hf_bin is None:
        return {"ok": False, "error": "hf CLI not found on PATH."}

    cmd = [str(hf_bin), "download", repo_id,
           "--include", "transformer-dev.safetensors",
           "--local-dir", str(local_dir)]

    env = dict(os.environ)
    hf_token = _active_hf_token()
    if hf_token:
        env["HF_TOKEN"] = hf_token
        env["HUGGING_FACE_HUB_TOKEN"] = hf_token

    with DOWNLOAD_LOCK:
        DOWNLOAD["active"] = True
        DOWNLOAD["key"] = "ltx_dev_transformer"
        DOWNLOAD["repo_id"] = repo_id
        DOWNLOAD["started_ts"] = time.time()
        DOWNLOAD["last_line"] = ""

    def _runner():
        try:
            push_log(f"[hf] dev transformer download started "
                     f"({repo_id} / transformer-dev.safetensors, ~11 GB).")
            proc = subprocess.Popen(
                cmd, stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                text=True, bufsize=1, env=env, start_new_session=True)
            with DOWNLOAD_LOCK:
                DOWNLOAD["proc"] = proc
                try:
                    DOWNLOAD["pgid"] = os.getpgid(proc.pid)
                except ProcessLookupError:
                    DOWNLOAD["pgid"] = None
            buf = ""
            assert proc.stdout is not None
            while True:
                ch = proc.stdout.read(1)
                if not ch:
                    break
                if ch in ("\n", "\r"):
                    line = buf.strip()
                    buf = ""
                    if line:
                        with DOWNLOAD_LOCK:
                            DOWNLOAD["last_line"] = line[:200]
                        push_log(f"[hf:dev] {line[:300]}")
                else:
                    buf += ch
            rc = proc.wait()
            if rc == 0:
                push_log("[hf] dev transformer downloaded successfully.")
            else:
                push_log(f"[hf] dev transformer download exited with code {rc}.")
        except Exception as exc:
            push_log(f"[hf] dev transformer crashed: {exc}")
        finally:
            with DOWNLOAD_LOCK:
                DOWNLOAD["active"] = False
                DOWNLOAD["key"] = None
                DOWNLOAD["repo_id"] = None
                DOWNLOAD["started_ts"] = None
                DOWNLOAD["last_line"] = ""
                DOWNLOAD["proc"] = None
                DOWNLOAD["pgid"] = None

    threading.Thread(target=_runner, daemon=True, name="hf-dev-download").start()
    return {"ok": True, "started": True, "repo_id": repo_id,
            "filename": "transformer-dev.safetensors"}


# Compatibility taxonomy for LoRAs across the panel's two render lanes
# (video via ltx_pipelines_mlx + image via mflux). The picker filters its
# library down to LoRAs that can fire with the user's current
# (mode, engine) selection. Source of truth is the CivitAI sidecar's
# `base_model` field; we map that to one or more compat tags.
#
# Compat tag vocabulary used throughout the panel + JS picker:
#   "video"           — LTX-Video LoRAs (any t2v / i2v / keyframe / extend)
#   "image:flux1"     — FLUX.1 [dev] / [schnell] (mflux flux1 family)
#   "image:flux2"     — FLUX.2 (klein-4b) base + Klein-Edit (flux2 + flux2_edit)
#   "image:qwen"      — Qwen-Image / Qwen-Image-Edit (qwen + qwen_edit)
#   "image:sdxl"      — SDXL 1.0 (mflux doesn't run SDXL today; flag for future)
#   "image:z_image"   — Z-Image / Z-Image Turbo (no LoRAs known yet)
#   "image:kontext"   — FLUX.1 Kontext-dev (image-conditioning family)
#   "unknown"         — sidecar missing base_model, or string we can't map.
#                       Surfaced in EVERY filter with a `?` indicator so the
#                       user can still try it (better to show + warn than to
#                       hide and leave the user confused).
def _classify_lora_modes(base_model) -> list[str]:
    """Map a CivitAI `base_model` sidecar string to compat tags.

    CivitAI is wildly inconsistent on this field — different uploaders
    write `Flux.1 D`, `flux 1 d`, `FLUX1`, `Flux1.D`, etc. for the same
    family. We lowercase + substring-match generously rather than
    exact-match. Returns a list because some LoRAs cover both the
    distilled + base flavors of one family.

    Anything we can't classify returns ["unknown"] so the picker can
    still surface it (with a `?` indicator) instead of silently hiding.
    """
    if not base_model:
        return ["unknown"]
    s = str(base_model).strip().lower()
    if not s:
        return ["unknown"]
    # Strip non-alphanumerics into a normalized lookup form so all of
    # "Flux.1 D", "flux1.d", "FLUX-1-D" collapse to "flux1d".
    norm = "".join(ch for ch in s if ch.isalnum())

    tags: list[str] = []
    # ---- Video lane (LTX-Video) ----
    # CivitAI strings include "LTXV 2.3", "LTX-Video", "LTX-2", "LTXV2.3".
    if "ltx" in norm:
        tags.append("video")
    # ---- Image lane: Qwen ----
    # "Qwen Image", "Qwen-Image-Edit", "Qwen Image Edit 2511" → image:qwen.
    if "qwen" in norm:
        tags.append("image:qwen")
    # ---- Image lane: FLUX.2 ----
    # Match BEFORE the FLUX.1 branch so "flux2" / "flux2d" don't fall
    # through to flux1 via the leading "flux" substring.
    if "flux2" in norm or "flux20" in norm:
        tags.append("image:flux2")
    elif "kontext" in norm:
        # FLUX.1 Kontext is its own image-conditioning model. Tag
        # separately so the kontext_high engine can filter cleanly.
        tags.append("image:kontext")
    elif "flux" in norm and "flux2" not in norm:
        # Catch flux1d, flux1s, flux1, "flux 1", "flux.1 d". The broader
        # `"flux" in norm` is enough for the FLUX.1 family.
        tags.append("image:flux1")
    # ---- Image lane: SDXL ----
    if "sdxl" in norm or "sd_xl" in norm:
        tags.append("image:sdxl")
    # ---- Image lane: Z-Image ----
    if "zimage" in norm or "ztoimage" in norm:
        tags.append("image:z_image")

    return tags or ["unknown"]


def _read_lora_sidecar(safetensors_path: Path) -> dict:
    """Read sidecar JSON next to a .safetensors LoRA. Falls back to bare
    filename + zero metadata when no sidecar is present, so users can
    drop in a raw .safetensors and get a usable picker entry without
    writing any metadata themselves.

    Sidecar schema (inspired by CivitAI's model JSON, kept compatible
    so a CivitAI download just writes its native shape):

      {
        "name": "Cinematic Post-Apocalyptic",
        "description": "...",
        "trigger_words": ["postapoc", "wasteland"],   // optional
        "recommended_strength": 0.8,                   // 0.0..1.5 typical
        "civitai_id": 2563394,                         // optional
        "civitai_version_id": 2880457,                 // optional
        "preview_url": "https://...",                  // optional
        "base_model": "LTXV 2.3",
        "downloaded_at": "2026-05-01T..."
      }
    """
    sidecar = safetensors_path.with_suffix(".json")
    meta = {
        "name": safetensors_path.stem.replace("_", " ").replace("-", " "),
        "description": "",
        "trigger_words": [],
        "recommended_strength": 1.0,
        "preview_url": None,
        "preview_type": None,        # "image" | "video" | None
        "base_model": None,
        "civitai_id": None,
        "civitai_version_id": None,
        "civitai_url": None,         # link back to source page (for "read instructions")
        "downloaded_at": None,
        # Optional local guardrail for style LoRAs that over-learn particle /
        # mesh artifacts. When present, make_job appends these to Avoid.
        "artifact_negative_prompt": "",
        # `kind` discriminates source: "train_character" for LoRAs produced
        # by Phosphene's in-app trainer, anything else (or absent) for
        # CivitAI / manual installs. The picker uses this to badge trained
        # LoRAs distinctly so users can find their own characters fast.
        "kind": None,
    }
    if sidecar.exists():
        try:
            with sidecar.open("r") as fh:
                user = json.load(fh) or {}
            for k in meta:
                if k in user and user[k] is not None:
                    meta[k] = user[k]
        except Exception as exc:
            sys.stderr.write(f"WARN: bad sidecar at {sidecar} ({exc}); "
                             f"falling back to filename\n")
    return meta


def list_user_loras() -> list[dict]:
    """Scan mlx_models/loras/ and return one entry per .safetensors found.
    Filenames are matched case-insensitive on the extension; subdirectories
    are not recursed (keeps the picker flat, no organizational ambiguity)."""
    out: list[dict] = []
    if not LORAS_DIR.exists():
        return out
    for path in sorted(LORAS_DIR.iterdir()):
        if not path.is_file() or path.suffix.lower() != ".safetensors":
            continue
        try:
            size_bytes = path.stat().st_size
        except OSError:
            continue
        meta = _read_lora_sidecar(path)
        # Heuristic: if preview_type wasn't recorded in the sidecar (older
        # downloads pre-this-field), infer from the URL extension so the UI
        # picks <video> vs <img> correctly.
        preview_url = meta.get("preview_url")
        preview_type = meta.get("preview_type")
        if preview_url and not preview_type:
            preview_type = "video" if preview_url.lower().split("?")[0].endswith(".mp4") else "image"
        # Backfill civitai_url from civitai_id when the sidecar predates the
        # explicit civitai_url field.
        civitai_url = meta.get("civitai_url")
        if not civitai_url and meta.get("civitai_id"):
            civitai_url = f"https://civitai.com/models/{meta.get('civitai_id')}"
        out.append({
            "id": f"user:{path.name}",
            "name": meta["name"],
            "description": meta["description"],
            "path": str(path),
            "filename": path.name,
            "size_bytes": size_bytes,
            "trigger_words": list(meta.get("trigger_words") or []),
            "recommended_strength": float(meta.get("recommended_strength") or 1.0),
            "preview_url": preview_url,
            "preview_type": preview_type,
            "base_model": meta.get("base_model"),
            "kind": meta.get("kind"),    # "train_character" for in-app trained LoRAs
            # Compat tags (see _classify_lora_modes). The picker uses
            # this to filter the library down to LoRAs that can actually
            # fire with the user's CURRENT (mode, engine) selection. An
            # "unknown" tag means we couldn't classify the sidecar's
            # base_model — surface in every filter with a `?` chip so
            # the user can still try it.
            "compatible_modes": _classify_lora_modes(meta.get("base_model")),
            "civitai_id": meta.get("civitai_id"),
            "civitai_version_id": meta.get("civitai_version_id"),
            "civitai_url": civitai_url,
            "downloaded_at": meta.get("downloaded_at"),
            "is_curated": False,
        })
    return out


def _lora_artifact_negative_prompt(loras: list[dict]) -> str:
    """Collect sidecar-defined artifact Avoid terms for active LoRAs.

    Some style LoRAs intentionally learn lighting / grade but also pick up
    unwanted dataset habits like glowing particle fields or tiled mesh
    textures. A local sidecar can carry `artifact_negative_prompt` so the
    panel applies that guard whenever the LoRA is active, without hard-coding
    one-off LoRA names in the helper.
    """
    additions: list[str] = []
    seen: set[str] = set()
    for entry in loras or []:
        path_raw = str((entry or {}).get("path") or "").strip()
        if not path_raw:
            continue
        try:
            strength = float((entry or {}).get("strength", 1.0))
        except (TypeError, ValueError):
            strength = 1.0
        if strength == 0:
            continue
        path = Path(path_raw)
        if not path.is_file():
            continue
        neg = str(_read_lora_sidecar(path).get("artifact_negative_prompt") or "").strip()
        if not neg:
            continue
        key = neg.lower()
        if key in seen:
            continue
        additions.append(neg)
        seen.add(key)
    return ", ".join(additions)


def list_curated_loras() -> list[dict]:
    """Curated entries surfaced in the UI even though the actual weights
    are pulled lazily from HuggingFace at first use. We hide the HDR one
    from the picker because it's exposed as a plain toggle elsewhere
    (see is_hdr_toggle filtering on the JS side)."""
    return [dict(v) for v in CURATED_LORAS.values()]


# ---- Characters discovery ----------------------------------------------------
#
# A "character" is a paired face + audio LoRA bundle trained in lora-lab.
# Discovery scans mlx_models/loras/ for files matching `<trigger>_v2.safetensors`
# and looks for the matching `<trigger>.audio.safetensors`. Metadata
# (display name, pronoun, subject_noun, default_action) is read from
# mlx_models/characters/<trigger>/bundle.json when present.
#
# This drives the Characters tab — see GET /characters,
# GET /characters/<id>/preview, POST /characters/<id>/generate.

_CHARACTERS_ID_RE = re.compile(r"^[A-Za-z0-9_-]+$")
_CHARACTERS_PREVIEW_LOCK = threading.Lock()
_CHARACTERS_CACHE_PATH = MODELS_DIR / "characters"
# Styles mirror the characters cache layout: mlx_models/styles/<trigger>/
# holds avatar.{ext} (first training frame) + optional bundle.json. The style
# id-validation regex piggybacks on _CHARACTERS_ID_RE — same [A-Za-z0-9_-]+
# rule, no point in two regexes.
_STYLES_CACHE_PATH = MODELS_DIR / "styles"


def _character_safe_id(value: str) -> str:
    """Validate a character id from a URL path. Trigger ids ship as
    [A-Za-z0-9_-]+ — anything else is path traversal or junk."""
    v = (value or "").strip()
    if not v or not _CHARACTERS_ID_RE.match(v):
        raise ValueError("invalid character id")
    return v


def _character_dataset_image(trigger: str) -> Path | None:
    """Find the most representative training image for `trigger`.

    Lookup order (first match wins):
      1. mlx_models/characters/<trigger>/avatar.{jpg,jpeg,png,webp} —
         panel-owned avatar. Written by run_train_job_inner after a
         successful face training (copies the first training image).
         New characters created via the Train tab end up here.
      2. lora-lab/dataset_<stem>_v2/images/<trigger>_001.png — the
         lora-lab convention Salo set up manually for ariatrn / bizarrotrn
         pre-Train-tab automation. <stem> = trigger with trailing 'trn'
         stripped (ariatrn → aria).
      3. lora-lab/dataset_<stem>*/images/<trigger>_*.png — any glob match
         under any dataset_<stem>* subdir (legacy fallback).
    Returns None when nothing resolvable exists — the UI paints a
    letter placeholder.
    """
    # 1. Panel-owned avatar (Train-tab convention).
    char_dir = _CHARACTERS_CACHE_PATH / trigger
    if char_dir.is_dir():
        for ext in (".jpg", ".jpeg", ".png", ".webp"):
            avatar = char_dir / f"avatar{ext}"
            if avatar.is_file():
                return avatar
    # 2 + 3. lora-lab conventions (legacy / manual).
    lab_root = Path("/Users/salo/AI/projects/lora-lab")
    stem = trigger[:-3] if trigger.endswith("trn") else trigger
    candidates = [
        lab_root / f"dataset_{stem}_v2" / "images" / f"{trigger}_001.png",
        lab_root / f"dataset_{stem}" / "images" / f"{trigger}_001.png",
    ]
    for c in candidates:
        if c.is_file():
            return c
    if lab_root.is_dir():
        for child in sorted(lab_root.glob(
                f"dataset_{stem}*/images/{trigger}_*.png")):
            if child.is_file():
                return child
    return None


def _character_bundle(trigger: str) -> dict:
    """Read mlx_models/characters/<trigger>/bundle.json if present.
    Returns an empty dict on missing or unparseable JSON — discovery
    still surfaces the character, just with reduced metadata."""
    bundle_path = _CHARACTERS_CACHE_PATH / trigger / "bundle.json"
    if not bundle_path.is_file():
        return {}
    try:
        return json.loads(bundle_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return {}


def list_characters() -> list[dict]:
    """Scan mlx_models/loras/ for character LoRAs and return one record per
    discovered character.

    Discovery rules:
      - face_lora  = `<trigger>_v2.safetensors`                  (REQUIRED)
      - audio_lora = `<trigger>.audio.safetensors` (same dir)    (optional)
      - voice_sample = `<trigger>.voice.<ext>`     (same dir)    (optional)
      - bundle = mlx_models/characters/<trigger>/bundle.json     (optional)
      - sample_image = first training image in lora-lab's dataset dir

    Characters without an audio LoRA are "silent" — they can still drive
    video generation (the face LoRA alone is enough for identity), but
    callers should skip audio cues in their prompts. `has_voice` exposes
    that state to the UI so a Silent badge + disabled audio toggle can
    render appropriately.
    """
    loras_dir = _safe_loras_dir()
    if not loras_dir.is_dir():
        return []
    voice_exts = sorted(TRAIN_VOICE_EXTS)
    out: list[dict] = []
    for face_path in sorted(loras_dir.glob("*_v2.safetensors")):
        trigger = face_path.name[: -len("_v2.safetensors")]
        if not _CHARACTERS_ID_RE.match(trigger):
            continue
        audio_path = loras_dir / f"{trigger}.audio.safetensors"
        has_audio = audio_path.is_file()
        # Look for any voice sample with a supported extension; pick the
        # first match in TRAIN_VOICE_EXTS order. The Train tab writes
        # whatever extension the user uploaded.
        voice_sample_path: Path | None = None
        for ext in voice_exts:
            candidate = loras_dir / f"{trigger}.voice{ext}"
            if candidate.is_file():
                voice_sample_path = candidate
                break
        bundle = _character_bundle(trigger)
        sample = _character_dataset_image(trigger)
        out.append({
            "id": trigger,
            "trigger": trigger,
            "name": bundle.get("name") or trigger.replace("trn", "").title() or trigger,
            "pronoun": bundle.get("pronoun") or "they",
            "subject_noun": bundle.get("subject_noun") or "person",
            "default_action": bundle.get("default_action") or "",
            "sexy_directive": bool(bundle.get("sexy_directive", False)),
            "face_lora_path": str(face_path),
            # Legacy field — present iff the audio LoRA exists. New callers
            # should prefer `audio_lora` + `has_voice` for clarity.
            "audio_lora_path": str(audio_path) if has_audio else None,
            "audio_lora": str(audio_path) if has_audio else None,
            "voice_sample": str(voice_sample_path) if voice_sample_path else None,
            # Back-compat alias — some older calls used `voice_wav_path`
            # specifically (assumed .wav). New callers should use
            # `voice_sample`.
            "voice_wav_path": str(voice_sample_path) if voice_sample_path else None,
            "has_voice": has_audio,
            "sample_image_path": str(sample) if sample else None,
            "sample_image_url": (f"/characters/{trigger}/preview"
                                 if sample else None),
        })
    return out


def _style_dataset_image(trigger: str) -> Path | None:
    """Find the avatar image for a trained style. Mirrors
    `_character_dataset_image` but only checks the panel-owned styles cache —
    styles don't have a lora-lab legacy convention to fall back on.

    Returns the first avatar.{jpg,jpeg,png,webp} under
    mlx_models/styles/<trigger>/ or None if no avatar is on disk.
    """
    style_dir = _STYLES_CACHE_PATH / trigger
    if not style_dir.is_dir():
        return None
    for ext in (".jpg", ".jpeg", ".png", ".webp"):
        avatar = style_dir / f"avatar{ext}"
        if avatar.is_file():
            return avatar
    return None


def list_styles() -> list[dict]:
    """Scan mlx_models/loras/ for STYLE LoRAs and return one record per
    discovered style. Parallel to `list_characters()` but the discovery rule
    is the `<trigger>.style.safetensors` naming convention rather than the
    `<trigger>_v2.safetensors` character convention. Style LoRAs are
    standalone — there's no paired audio LoRA, no voice sample.

    Returns: [{trigger, name, lora_path, created_at, rank, steps,
               image_count, sample_image_path, sample_image_url}]
    """
    loras_dir = _safe_loras_dir()
    if not loras_dir.is_dir():
        return []
    out: list[dict] = []
    for style_path in sorted(loras_dir.glob("*.style.safetensors")):
        # Strip the ".style.safetensors" suffix to recover the trigger.
        trigger = style_path.name[: -len(".style.safetensors")]
        if not _CHARACTERS_ID_RE.match(trigger):
            continue
        # Read sibling sidecar JSON for metadata (rank, steps, etc.). Missing
        # sidecar isn't fatal — the LoRA still surfaces, just with reduced
        # metadata.
        sidecar_path = loras_dir / f"{trigger}.style.json"
        meta: dict = {}
        if sidecar_path.is_file():
            try:
                meta = json.loads(sidecar_path.read_text(encoding="utf-8")) or {}
            except (OSError, json.JSONDecodeError):
                meta = {}
        try:
            stat = style_path.stat()
        except OSError:
            continue
        sample = _style_dataset_image(trigger)
        out.append({
            "id": trigger,
            "trigger": trigger,
            "name": meta.get("name") or trigger,
            "lora_path": str(style_path),
            "filename": style_path.name,
            "size_mb": round(stat.st_size / (1024 * 1024), 1),
            "created_at": meta.get("created_at") or stat.st_mtime,
            "preset": meta.get("preset") or "",
            "rank": meta.get("rank"),
            "steps": meta.get("steps"),
            "resolution": meta.get("resolution"),
            "image_count": meta.get("image_count") or 0,
            "recommended_strength": float(meta.get("recommended_strength") or 1.0),
            "sample_image_path": str(sample) if sample else None,
            "sample_image_url": (f"/styles/{trigger}/preview"
                                 if sample else None),
        })
    return out


# Duration in seconds → frames the LTX 2.3 pipeline accepts. The
# constraint is `frames % 8 == 1`; 121 / 169 / 241 satisfy that and
# correspond to 5s / 7s / 10s at 24 fps.
_CHARACTER_DURATION_FRAMES = {
    "5s": 121,
    "7s": 169,
    "10s": 241,
}

# Quality-to-resolution map for the Characters tab. Nothing else.
# 2026-05-16 — Salo's call: stop translating the user's request through
# a 25-field "locked recipe" composer. The Characters endpoint is now a
# thin wrapper around /queue/add that uses identical defaults; the only
# things the tab adds are the LoRA stack lookup and the duration→frames
# / quality→resolution mappings.
_CHARACTER_QUALITY_RESOLUTION = {
    "draft":    (736, 416),    # ~3:30 wall for 7s, Q8 HQ, lower per-frame detail
    "balanced": (1024, 576),   # reserved for a real fast-but-quality-equal tier
    "high":     (1024, 576),   # locked production recipe
}


# ---- Version check / update notifier ----------------------------------------
# Phosphene ships fixes often (multiple commits a day in active periods) and
# users keep telling us "I clicked Update but I don't see anything new" — by
# the time their feedback lands, we've usually pushed three more commits.
# This module surfaces a small "Update available" pill in the header when the
# local install is behind origin/main, so users notice mismatch immediately
# instead of finding out later via a friend's tweet.
#
# How it works:
#   1. At startup we read the local commit SHA via `git rev-parse HEAD` and
#      branch name via `git rev-parse --abbrev-ref HEAD`. Stored once.
#   2. A daemon thread polls the GitHub commits API every 30 minutes (no
#      auth, public repo, well within unauthenticated rate limit).
#   3. We list `origin/main` commits newest-first and find the index of the
#      local SHA. If found at index N, we are N commits behind. If not found
#      in the first 30 commits, we report "30+ behind".
#   4. The /version endpoint returns the snapshot; the UI renders a pill
#      that links to the version modal listing each unseen commit.
#
# Suppressed cases (no pill rendered):
#   - User is on a non-main branch (local dev / fork)
#   - User has uncommitted local changes (in-progress work; we'd be wrong
#     to call them "behind")
#   - We can't reach the GitHub API (offline; suppress silently — we don't
#     bug users with red error toasts every 30 minutes)

_VERSION_LOCK = threading.Lock()
_VERSION_REPO_OWNER = "mrbizarro"
_VERSION_REPO_NAME = "phosphene"
_VERSION_POLL_INTERVAL_SEC = 30 * 60          # 30 minutes between checks
_VERSION_STARTUP_DELAY_SEC = 30                # don't compete with boot
_VERSION_STATE: dict = {
    "local_sha": None,            # 40-char hex of HEAD at panel start
    "local_short": None,           # 7-char display form
    "local_version": None,         # human label from /VERSION file (e.g. "Y1.001")
    "local_branch": None,          # branch name (e.g. "main") or "(detached)"
    "local_dirty": False,          # uncommitted changes in the working tree
    "remote_sha": None,            # latest sha on origin/main per GitHub API
    "remote_short": None,
    "remote_version": None,        # /VERSION file at origin/main (raw fetch)
    "behind_by": 0,                # number of commits between local and remote (0 = current)
    "behind_more_than": False,     # True when behind > 30 (we cap the API response)
    "commits_ahead": [],           # list of {sha, short, message, author, date} for the dropdown
    "checked_ts": None,            # epoch seconds of last successful poll
    "error": None,                 # last failure reason (None when last check OK)
    "suppress_reason": None,       # set when we deliberately skip checking (dev mode, dirty, etc.)
    # Pull state — populated only when the user clicks the magic button on
    # the pill while behind. Kept on _VERSION_STATE so the UI can render a
    # "restart needed" pill without a separate state store.
    "pull_state": "idle",          # idle | pulling | pulled | error
    "pull_message": None,          # human-readable result line (last git output line, or error)
    "pull_pulled_to_short": None,  # SHA we ended up at after the pull
    "pull_pulled_to_version": None,# VERSION label after the pull
    "pull_requires_full_update": False,  # True if the diff touched deps/patches
}


def _git_capture(args: list[str], cwd: Path = ROOT) -> str | None:
    """Run a git subcommand and return stripped stdout (or None on any failure).
    No exceptions ever escape — we never want a missing git binary to crash
    the panel boot."""
    try:
        out = subprocess.check_output(
            ["git"] + args, cwd=str(cwd), stderr=subprocess.DEVNULL,
        )
        return out.decode("utf-8", "replace").strip()
    except (subprocess.CalledProcessError, FileNotFoundError, OSError):
        return None


def _read_local_version() -> str | None:
    """Return the contents of <repo>/VERSION as a single stripped string,
    or None if the file is missing / unreadable. We use this to surface a
    human-friendly label like 'Y1.001' instead of raw 7-char SHAs in the
    header pill. Older checkouts that predate this file fall back to the
    short SHA in the UI without breaking."""
    try:
        v = (ROOT / "VERSION").read_text().strip()
        return v or None
    except Exception:
        return None


def _fetch_raw_text(url: str, timeout: int = 10) -> str | None:
    """GET a public URL and return its body as a stripped string, or None
    on any error. Used for the raw VERSION-file fetch from origin/main on
    GitHub — `https://raw.githubusercontent.com/.../main/VERSION`. No
    auth, no rate-limit headers worth honouring at this volume (one
    request per 30-min poll)."""
    import urllib.request as _urlreq
    try:
        req = _urlreq.Request(url, headers={"User-Agent": "phosphene-panel-version-check"})
        with _urlreq.urlopen(req, timeout=timeout) as resp:
            return resp.read().decode("utf-8", "replace").strip() or None
    except Exception:
        return None


def _detect_local_install_state() -> None:
    """Populate _VERSION_STATE.local_* fields. Called once at startup; result
    doesn't change while the panel is running (no auto-pull on the user's
    behalf). Pinokio's Update step kills + restarts the panel, so a fresh
    detect runs after every Update."""
    sha = _git_capture(["rev-parse", "HEAD"])
    branch = _git_capture(["rev-parse", "--abbrev-ref", "HEAD"]) or "(unknown)"
    # `git status --porcelain` empty = clean tree.
    porcelain = _git_capture(["status", "--porcelain"])
    dirty = bool(porcelain and porcelain.strip())
    local_version = _read_local_version()
    with _VERSION_LOCK:
        _VERSION_STATE["local_sha"] = sha
        _VERSION_STATE["local_short"] = sha[:7] if sha else None
        _VERSION_STATE["local_version"] = local_version
        _VERSION_STATE["local_branch"] = branch
        _VERSION_STATE["local_dirty"] = dirty
        # Suppress remote checks when the user is clearly running their own
        # variant — we'd be wrong to nag them about being "behind."
        if not VERSION_CHECK_ENABLED:
            _VERSION_STATE["suppress_reason"] = "disabled by PHOSPHENE_DISABLE_VERSION_CHECK"
        elif not sha:
            _VERSION_STATE["suppress_reason"] = "not a git checkout"
        elif branch != "main":
            _VERSION_STATE["suppress_reason"] = f"on branch '{branch}', not main"
        elif dirty:
            _VERSION_STATE["suppress_reason"] = "local changes uncommitted"
        else:
            _VERSION_STATE["suppress_reason"] = None


def _fetch_remote_commits(limit: int = 30) -> list[dict] | None:
    """GET the latest N commits on origin/main from the public GitHub API.
    Returns a list of raw commit dicts (newest first), or None on any error.
    Caller is expected to handle None gracefully — we don't show errors to
    the user every 30 minutes when their wifi is flaky."""
    import urllib.request as _urlreq
    import urllib.error as _urlerr
    url = (f"https://api.github.com/repos/{_VERSION_REPO_OWNER}/"
           f"{_VERSION_REPO_NAME}/commits?sha=main&per_page={limit}")
    req = _urlreq.Request(url, headers={
        "Accept": "application/vnd.github+json",
        "User-Agent": "phosphene-panel-version-check",
    })
    try:
        with _urlreq.urlopen(req, timeout=10) as resp:
            data = json.loads(resp.read().decode("utf-8"))
        if not isinstance(data, list):
            return None
        return data
    except (_urlerr.URLError, _urlerr.HTTPError, OSError, ValueError, TimeoutError):
        return None


def _check_remote_once() -> None:
    """Run one remote check, mutate _VERSION_STATE accordingly. Idempotent.
    Safe to call from a background thread or from a /version/check endpoint.
    Re-detects local state (HEAD, branch, dirty) at the top of every call so
    a tree that was dirty when the panel started but is clean now (e.g. user
    just committed) gets picked up without needing a panel restart. The
    earlier build only ran _detect_local_install_state once at startup,
    which left the suppress_reason stale across the panel's lifetime."""
    _detect_local_install_state()
    with _VERSION_LOCK:
        suppress = _VERSION_STATE["suppress_reason"]
        local_sha = _VERSION_STATE["local_sha"]
    if suppress:
        return                             # never poll in suppressed states
    commits = _fetch_remote_commits(limit=30)
    if commits is None:
        with _VERSION_LOCK:
            _VERSION_STATE["error"] = "could not reach github.com"
        return
    if not commits:
        with _VERSION_LOCK:
            _VERSION_STATE["error"] = "github returned no commits"
        return
    remote_sha = commits[0].get("sha")
    if not remote_sha:
        with _VERSION_LOCK:
            _VERSION_STATE["error"] = "github response missing sha"
        return

    # Find local SHA in the list. If it's at index N, we are N commits behind.
    behind_by = None
    for i, c in enumerate(commits):
        if c.get("sha") == local_sha:
            behind_by = i
            break
    if behind_by is None:
        # Local is older than what fits in the window OR has been rebased
        # away. Either way, "30+" is a fine UX answer — the modal will say
        # "many updates available, please run Pinokio Update."
        behind_by = len(commits)
        more = True
    else:
        more = False

    # Slim each commit dict down to what the modal renders. Keep only the
    # commits the user is missing.
    ahead: list[dict] = []
    for c in commits[:behind_by]:
        commit = c.get("commit") or {}
        author = (commit.get("author") or {}).get("name") or "unknown"
        date = (commit.get("author") or {}).get("date") or ""
        msg = (commit.get("message") or "").splitlines()[0]   # first line only
        sha = c.get("sha") or ""
        ahead.append({
            "sha": sha,
            "short": sha[:7],
            "message": msg,
            "author": author,
            "date": date,
        })

    # Fetch the upstream VERSION file in parallel with the commits API so
    # the pill can show the human-friendly label (Y1.NNN). This is a raw
    # GET on raw.githubusercontent.com — no rate limit concern at our
    # 30-min cadence. Tolerate missing-file silently: older origin/main
    # commits predate VERSION, and we still have the SHA fallback.
    remote_version = _fetch_raw_text(
        f"https://raw.githubusercontent.com/{_VERSION_REPO_OWNER}/"
        f"{_VERSION_REPO_NAME}/main/VERSION"
    )
    with _VERSION_LOCK:
        _VERSION_STATE["remote_sha"] = remote_sha
        _VERSION_STATE["remote_short"] = remote_sha[:7]
        _VERSION_STATE["remote_version"] = remote_version
        _VERSION_STATE["behind_by"] = behind_by
        _VERSION_STATE["behind_more_than"] = more
        _VERSION_STATE["commits_ahead"] = ahead
        _VERSION_STATE["checked_ts"] = time.time()
        _VERSION_STATE["error"] = None


def version_check_loop() -> None:
    """Daemon thread entry: detect local state once, then poll the remote
    every _VERSION_POLL_INTERVAL_SEC. First poll happens after a 30s
    delay so we don't compete with boot-time work."""
    _detect_local_install_state()
    time.sleep(_VERSION_STARTUP_DELAY_SEC)
    while True:
        try:
            _check_remote_once()
        except Exception as exc:                          # belt + braces
            sys.stderr.write(f"WARN: version check raised: {exc}\n")
        time.sleep(_VERSION_POLL_INTERVAL_SEC)


def get_version_state() -> dict:
    """Snapshot of _VERSION_STATE for the /version endpoint. Returns a copy
    so the caller can't mutate the live state under the lock."""
    with _VERSION_LOCK:
        return dict(_VERSION_STATE)


def parse_loras_from_form(form: dict) -> list[dict]:
    """Parse the loras=<JSON> form field that the UI submits with each job.
    Shape on the wire is a JSON array of {id, path, strength}. We trust
    `id` only for routing in this layer; what gets sent to the helper is
    just the (path, strength) pair the fuser needs."""
    raw = form.get("loras", [""])
    if isinstance(raw, list):
        raw = raw[0] if raw else ""
    raw = (raw or "").strip()
    if not raw:
        return []
    try:
        items = json.loads(raw)
    except json.JSONDecodeError:
        return []
    out: list[dict] = []
    if not isinstance(items, list):
        return out
    for item in items:
        if not isinstance(item, dict):
            continue
        path = str(item.get("path") or "").strip()
        if not path:
            continue
        try:
            strength = float(item.get("strength", 1.0))
        except (TypeError, ValueError):
            strength = 1.0
        # Clamp; LoRA strengths beyond ±2 are usually nonsense and risk
        # numerical issues during fusion.
        strength = max(-2.0, min(2.0, strength))
        out.append({"path": path, "strength": strength})
    return out


def _repos() -> list[dict]:
    """All repo entries from required_files.json (list, in order)."""
    return list(_REQUIRED.get("repos", []))


def _repo_missing(repo: dict) -> list[str]:
    """Files missing or zero-byte for one repo, expressed as bare filenames
    (relative to the repo's local_dir). Bare names are friendlier in the UI
    than full paths."""
    base = ROOT / repo["local_dir"]
    missing = []
    for fname in repo.get("files", []):
        p = base / fname
        try:
            if not p.exists() or p.stat().st_size < _MIN_FILE_BYTES:
                missing.append(fname)
        except OSError:
            missing.append(fname)
    return missing


def _repo_complete(repo: dict) -> bool:
    return not _repo_missing(repo)


# ---- HF cache fallback -------------------------------------------------------
# Background:
#   - Pinokio installs use `hf download --local-dir mlx_models/<repo>/`. Files
#     live at the canonical local_dir path the manifest declares.
#   - Manual / dev installs that pass an HF repo id as LTX_MODEL get the
#     weights resolved via huggingface_hub's cache at ~/.cache/huggingface/.
#     Same files, different location.
#
# Without this fallback, dev-env users whose models were already pulled into
# the HF cache (e.g. by an earlier `huggingface-cli download` or by the helper
# itself on first run) saw the panel report Q4 as "MISSING" even though every
# render was working perfectly. That was the confusing "honest note" — fixing
# it here so the modal honestly reflects "available, just not in mlx_models/".
def _hf_cache_root() -> Path:
    """Resolve HF cache root the same way huggingface_hub does — env vars
    in the order the library checks, falling back to ~/.cache/huggingface/hub."""
    explicit = (
        os.environ.get("HF_HUB_CACHE")
        or os.environ.get("HUGGINGFACE_HUB_CACHE")
    )
    if explicit:
        return Path(explicit)
    hf_home = os.environ.get("HF_HOME")
    if hf_home:
        return Path(hf_home) / "hub"
    return Path.home() / ".cache/huggingface/hub"


def _repo_hf_cache_dir(repo_id: str) -> Path | None:
    """Return the most recent snapshot dir for repo_id in the HF cache, or
    None if not present. Layout: <cache>/models--<owner>--<repo>/snapshots/<rev>/"""
    safe = repo_id.replace("/", "--")
    base = _hf_cache_root() / f"models--{safe}" / "snapshots"
    if not base.is_dir():
        return None
    revs = []
    try:
        for d in base.iterdir():
            if d.is_dir():
                revs.append((d, d.stat().st_mtime))
    except OSError:
        return None
    if not revs:
        return None
    revs.sort(key=lambda t: t[1], reverse=True)
    return revs[0][0]


def _repo_missing_in_cache(repo: dict) -> list[str] | None:
    """Files missing from the HF cache snapshot for this repo, or None if
    the repo isn't in the cache at all (caller treats None as "fall back to
    local-dir reporting"). HF cache stores symlinks to ../blobs/<hash>; we
    follow them and check size on the actual blob."""
    cache_dir = _repo_hf_cache_dir(repo["repo_id"])
    if cache_dir is None:
        return None
    missing = []
    for fname in repo.get("files", []):
        p = cache_dir / fname
        try:
            actual = p.resolve()
            if not actual.exists() or actual.stat().st_size < _MIN_FILE_BYTES:
                missing.append(fname)
        except OSError:
            missing.append(fname)
    return missing


def base_missing() -> list[str]:
    """Aggregate of all base-kind repos' missing files (each prefixed with
    its local_dir for backwards-compat with existing /status consumers).

    Only checks the canonical Pinokio layout. If LTX_MODEL is set to an HF
    repo id rather than a local path, the helper resolves weights via the
    HF cache and the local-dir check would misreport — return [] there so
    the panel doesn't false-positive against a working manual install."""
    if not str(MODEL_ID).startswith("/"):
        return []
    out = []
    for r in _repos():
        if r.get("kind") != "base":
            continue
        for fname in _repo_missing(r):
            out.append(f"{r['local_dir']}/{fname}")
    return out


def q8_missing_files() -> list[str]:
    """Files missing for the Q8 repo (bare filenames). Honors $LTX_Q8_LOCAL.

    When LTX_Q8_LOCAL is set, it overrides the Q8 repo's local_dir — we
    re-route the check there. Other overrides (e.g. moving Q4 elsewhere)
    aren't supported via env var; users with custom layouts should adjust
    required_files.json directly."""
    for r in _repos():
        if r.get("key") == "q8":
            override = r.copy()
            override["local_dir"] = str(Q8_LOCAL_PATH.relative_to(ROOT)) \
                if Q8_LOCAL_PATH.is_relative_to(ROOT) else str(Q8_LOCAL_PATH)
            # _repo_missing uses ROOT-relative; if Q8_LOCAL_PATH is absolute
            # outside ROOT, build a temporary repo with absolute base.
            if Path(override["local_dir"]).is_absolute():
                missing = []
                for fname in r.get("files", []):
                    p = Path(override["local_dir"]) / fname
                    try:
                        if not p.exists() or p.stat().st_size < _MIN_FILE_BYTES:
                            missing.append(fname)
                    except OSError:
                        missing.append(fname)
                return missing
            return _repo_missing(override)
    return []


def repo_status_list() -> list[dict]:
    """Per-repo status snapshot for the /models endpoint and the UI panel.

    Resolution order per repo:
      1. Check the canonical local_dir (mlx_models/<repo>/...) — what
         Pinokio installs always populate.
      2. If incomplete there, check HF cache (~/.cache/huggingface/...) —
         what manual installs / dev environments use.
      3. Whichever is more complete wins; the `where` field tells the UI
         which storage layer the files are in (so we can show "Cached"
         instead of "Installed" for cache-backed installs).

    This is the fix for the previously-reported false "MISSING" against
    HF-cache installs — the panel now sees them and reports honestly."""
    out = []
    for r in _repos():
        local_dir = r["local_dir"]
        if r.get("key") == "q8":
            local_dir = str(Q8_LOCAL_PATH)

        local_missing = q8_missing_files() if r.get("key") == "q8" else _repo_missing(r)
        total = len(r.get("files", []))
        local_present = total - len(local_missing)

        cache_missing = _repo_missing_in_cache(r)
        cache_present = (total - len(cache_missing)) if cache_missing is not None else 0

        # Pick the layer with more files present — ties go to local_dir
        # because that's what Pinokio installs use and what the menu
        # consults.
        if cache_missing is not None and cache_present > local_present:
            where = "hf_cache"
            missing = cache_missing
            present = cache_present
            location = str(_repo_hf_cache_dir(r["repo_id"]) or _hf_cache_root())
        else:
            where = "local_dir"
            missing = local_missing
            present = local_present
            location = local_dir

        out.append({
            "key": r["key"],
            "kind": r.get("kind", "base"),
            "name": r["name"],
            "blurb": r.get("blurb", ""),
            "repo_id": r["repo_id"],
            "local_dir": local_dir,
            "where": where,                 # 'local_dir' | 'hf_cache'
            "location": location,           # actual on-disk path the files are in
            "size_gb": r.get("size_gb"),
            "total_files": total,
            "present_files": present,
            "missing_files": missing,
            "complete": not missing,
        })
    return out


# ---- HF download (in-panel model fetcher) ------------------------------------
# `hf` is the v1+ huggingface_hub CLI. We resolve it from (in order):
#   1. $LTX_HF env var
#   2. ltx-2-mlx/.venv/bin/hf       (manual install)
#   3. ltx-2-mlx/env/bin/hf         (Pinokio)
#   4. shutil.which("hf")           (system PATH fallback)
def _resolve_hf() -> Path | None:
    candidates = [
        os.environ.get("LTX_HF"),
        str(MLX / ".venv/bin/hf"),
        str(MLX / "env/bin/hf"),
        shutil.which("hf"),
    ]
    for c in candidates:
        if c and Path(c).exists():
            return Path(c)
    return None


HF_BIN = _resolve_hf()

# Single global download slot — concurrent hf downloads compete for bandwidth
# anyway, and serializing them keeps the log readable. State protected by
# DOWNLOAD_LOCK; UI polls via /status to render progress.
DOWNLOAD_LOCK = threading.Lock()
DOWNLOAD: dict = {
    "active": False,
    "key": None,           # which repo (q4/gemma/q8)
    "repo_id": None,
    "started_ts": None,
    "last_line": "",       # most recent hf output line for UI display
    "proc": None,
    "pgid": None,
}


def _download_thread(repo: dict) -> None:
    """Run `hf download <repo_id> --local-dir <repo.local_dir>` and stream
    stdout/stderr line-by-line into STATE['log']. Sets DOWNLOAD["active"]
    back to False on exit (success or fail). Files land at repo['local_dir']
    relative to ROOT, which is exactly where the completeness checks look —
    so the moment hf finishes, /status flips to complete + the UI updates.

    Y1.022 — enables hf_transfer (Rust accelerator, ~5-10× faster on big
    repos) via env var, threads the user's HF token through if set
    (anonymous HF is throttled to ~50 KB/s and stalls Q8), and wraps the
    download in a 3-attempt retry loop with exponential backoff. hf is
    resumable, so retries pick up from where the previous attempt
    stopped. User cancellations (DOWNLOAD["active"] flipping to False)
    break the loop early."""
    repo_id = repo["repo_id"]
    target = ROOT / repo["local_dir"]
    target.mkdir(parents=True, exist_ok=True)
    cmd = [str(HF_BIN), "download", repo_id, "--local-dir", str(target)]
    # Y1.024 — apply --include filter when the repo entry declares one. Without
    # it `hf download` grabs every file in the upstream repo. dgrauet's LTX
    # repos host duplicate transformer variants (-distilled, -distilled-1.1,
    # -dev), duplicate distilled LoRAs, and unused upscalers — turning a
    # declared 25 GB Q8 into 82 GB on disk and a 25 GB Q4 into 56 GB.
    # `download_include` is the explicit allowlist of patterns we ship to
    # the user; everything else stays on the Hub. See required_files.json
    # for the comment block on this.
    include_patterns = repo.get("download_include") or []
    for pat in include_patterns:
        cmd.extend(["--include", pat])
    if include_patterns:
        push(f"[hf] filtering {repo_id} download to {len(include_patterns)} pattern(s) — only the files the panel actually loads.")
    push(f"[hf] {repo_id} → {target} (~{repo.get('size_gb','?')} GB) — resumable")

    # Build the env once. HF_HUB_ENABLE_HF_TRANSFER=1 turns on the Rust
    # downloader; if hf_transfer isn't installed the hf CLI logs a warning
    # and falls back to the Python downloader (slower but still works).
    # HF_TOKEN unlocks faster throughput for users who configured a token
    # in Settings — anonymous HF is throttled hard.
    env = os.environ.copy()
    env["HF_HUB_ENABLE_HF_TRANSFER"] = "1"
    hf_token = _active_hf_token()
    if hf_token:
        env["HF_TOKEN"] = hf_token
        env["HUGGING_FACE_HUB_TOKEN"] = hf_token
        push(f"[hf] using authenticated download (HF token configured) — ~10× faster than anonymous.")
    else:
        push(f"[hf] no HF token configured — downloads run on the throttled anonymous tier. Set one in Settings → Hugging Face token for ~10× faster downloads.")

    max_attempts = 3
    backoff_sec = 5
    try:
        for attempt in range(1, max_attempts + 1):
            with DOWNLOAD_LOCK:
                if not DOWNLOAD["active"]:
                    push(f"[hf] {repo_id} cancelled before attempt {attempt}.")
                    break
            if attempt > 1:
                push(f"[hf] {repo_id} attempt {attempt}/{max_attempts} — resuming from where the previous attempt stopped.")
            try:
                proc = subprocess.Popen(
                    cmd,
                    stdout=subprocess.PIPE,
                    stderr=subprocess.STDOUT,
                    text=True,
                    bufsize=1,
                    env=env,
                    start_new_session=True,
                )
            except Exception as exc:
                push(f"[hf] failed to spawn hf: {exc}")
                break
            with DOWNLOAD_LOCK:
                DOWNLOAD["proc"] = proc
                try:
                    DOWNLOAD["pgid"] = os.getpgid(proc.pid)
                except ProcessLookupError:
                    DOWNLOAD["pgid"] = None
            # Stream every line. hf emits a tqdm progress bar with carriage
            # returns; we split on \r as well as \n so progress updates show
            # up live in the panel log instead of being buffered until done.
            buf = ""
            while True:
                ch = proc.stdout.read(1)
                if not ch:
                    break
                if ch in ("\n", "\r"):
                    line = buf.strip()
                    buf = ""
                    if line:
                        with DOWNLOAD_LOCK:
                            DOWNLOAD["last_line"] = line[:200]
                        push(f"[hf:{repo['key']}] {line[:300]}")
                else:
                    buf += ch
            if buf.strip():
                push(f"[hf:{repo['key']}] {buf.strip()[:300]}")
            rc = proc.wait()
            if rc == 0:
                push(f"[hf] {repo_id} downloaded successfully.")
                break
            with DOWNLOAD_LOCK:
                still_active = DOWNLOAD["active"]
            if not still_active:
                push(f"[hf] {repo_id} cancelled (exit {rc}).")
                break
            if attempt < max_attempts:
                push(f"[hf] {repo_id} attempt {attempt} failed (exit {rc}). Retrying in {backoff_sec}s — hf will resume from the last completed file.")
                # Sleep in 1-second slices so a cancel during backoff is responsive.
                for _ in range(backoff_sec):
                    time.sleep(1)
                    with DOWNLOAD_LOCK:
                        if not DOWNLOAD["active"]:
                            break
                backoff_sec = min(backoff_sec * 2, 60)   # 5 → 10 → 20s cap by attempt 3
            else:
                push(f"[hf] {repo_id} FAILED after {max_attempts} attempts (last exit {rc}). Click Download again to keep retrying — hf will resume.")
    except Exception as exc:
        push(f"[hf] {repo_id} crashed: {exc}")
    finally:
        with DOWNLOAD_LOCK:
            DOWNLOAD["active"] = False
            DOWNLOAD["key"] = None
            DOWNLOAD["repo_id"] = None
            DOWNLOAD["started_ts"] = None
            DOWNLOAD["last_line"] = ""
            DOWNLOAD["proc"] = None
            DOWNLOAD["pgid"] = None


def _kill_active_download() -> None:
    """Best-effort kill the running hf process group. Called by atexit and
    by the /models/cancel endpoint."""
    with DOWNLOAD_LOCK:
        pgid = DOWNLOAD.get("pgid")
        proc = DOWNLOAD.get("proc")
    if pgid is not None:
        try:
            os.killpg(pgid, signal.SIGTERM)
        except (ProcessLookupError, PermissionError):
            pass
    elif proc is not None:
        try:
            proc.terminate()
        except Exception:
            pass


atexit.register(_kill_active_download)


# ---- CivitAI bridge ---------------------------------------------------------
# CivitAI is the de-facto LoRA distribution hub. We hit its public REST API
# (no auth required for SFW; an optional CIVITAI_API_KEY env var unlocks
# higher rate limits + NSFW listings tied to an account) and download via
# urllib so we don't need a third-party HTTP dependency.
#
# Filtering: baseModels=LTXV%202.3 + types=LORA narrows to LTX-2.3 LoRAs.
# CivitAI's response shape is documented at
# https://github.com/civitai/civitai/wiki/REST-API-Reference but we trim
# the response server-side so the panel only ships what the UI needs.

CIVITAI_API_BASE = "https://civitai.com/api/v1"
CIVITAI_USER_AGENT = "phosphene/1.0 (https://github.com/mrbizarro/phosphene)"


def _civitai_request(path: str, params: dict | None = None,
                     timeout: float = 20.0) -> dict:
    """Minimal stdlib HTTP client for the CivitAI API. No third-party
    deps so we don't pin requests / httpx into the install. Returns the
    decoded JSON body or raises RuntimeError on non-2xx."""
    import urllib.parse, urllib.request
    url = f"{CIVITAI_API_BASE}{path}"
    if params:
        # urlencode handles the URL-quoting (spaces → %20 etc.) so
        # baseModels=LTXV 2.3 makes it through unmangled.
        url = url + "?" + urllib.parse.urlencode(params, doseq=True)
    req = urllib.request.Request(url, headers={
        "Accept": "application/json",
        "User-Agent": CIVITAI_USER_AGENT,
    })
    api_key = _active_civitai_key()
    if api_key:
        req.add_header("Authorization", f"Bearer {api_key}")
    try:
        with urllib.request.urlopen(req, timeout=timeout) as resp:
            body = resp.read().decode("utf-8", "replace")
            return json.loads(body)
    except Exception as exc:
        raise RuntimeError(f"{type(exc).__name__}: {exc}") from exc


def _civitai_search(query: str = "", nsfw: bool = False,
                    cursor: str = "", limit: int = 20) -> dict:
    """Search LTX-2.3 LoRAs. Returns the trimmed shape:
        { "items": [{
            "id", "name", "creator", "description", "tags", "downloads",
            "rating", "nsfw", "preview_url", "version_id",
            "download_url", "trigger_words", "recommended_strength",
            "size_kb", "base_model"
          }, ...],
          "total_pages", "current_page" }
    Each item carries everything the front end needs to render a card
    AND everything the download endpoint needs to write a sidecar — no
    second round-trip required to install."""
    # Spicy mode gate (v2.0 — server-side authoritative). When the user
    # hasn't enabled Spicy mode in Settings, force nsfw=False regardless
    # of what the client sent. This keeps NSFW results out of casual /
    # kid-accessible installs even if someone fiddles the client param.
    spicy_on = bool(get_settings().get("spicy_mode", False))
    if not spicy_on:
        nsfw = False
    # CivitAI's /models endpoint uses cursor-style pagination
    # (`nextCursor` in the response → pass back as `cursor` on the next
    # request). Page numbers are deprecated for this endpoint. We expose
    # the same cursor flow to the panel UI so it can render a "Load more"
    # affordance without faking pagination on top of cursors.
    params: dict[str, object] = {
        "types": "LORA",
        "baseModels": "LTXV 2.3",
        "limit": limit,
        "sort": "Most Downloaded",
        # nsfw=True lets the API include NSFW results; the user's CivitAI
        # account-level filter (if any) is unaffected. We surface the
        # boolean on each item so the front end can render a warning.
        "nsfw": "true" if nsfw else "false",
    }
    if query.strip():
        params["query"] = query.strip()
    if cursor:
        params["cursor"] = cursor
    raw = _civitai_request("/models", params=params)
    items = []
    for m in (raw.get("items") or []):
        versions = m.get("modelVersions") or []
        if not versions:
            continue
        v = versions[0]
        files = v.get("files") or []
        # Pick the first .safetensors file. CivitAI sometimes hosts
        # multiple file variants (pruned, full, etc.); prefer the one
        # marked `primary: true` if present, otherwise fall back to the
        # first .safetensors.
        primary = next((f for f in files if f.get("primary") and
                        f.get("name", "").lower().endswith(".safetensors")),
                       None) or next((f for f in files if
                       f.get("name", "").lower().endswith(".safetensors")),
                       None)
        if not primary:
            continue
        images = v.get("images") or []
        # Prefer the first image-type preview if any exist (some LTX LoRAs
        # ship both video MP4s AND still images). Fall back to the first
        # entry of any type. We pass the type back to the client so the
        # renderer can pick <img> vs <video> appropriately — for LTX
        # video LoRAs the previews are usually MP4s, which would just
        # 404 inside an <img> tag.
        preview_obj = (
            next((img for img in images if img.get("type") == "image" and img.get("url")), None)
            or next((img for img in images if img.get("url")), None)
        )
        preview = preview_obj.get("url") if preview_obj else None
        preview_type = preview_obj.get("type") if preview_obj else None
        creator = (m.get("creator") or {}).get("username") or "unknown"
        # CivitAI puts trigger words on the version (`trainedWords`).
        trigger = list(v.get("trainedWords") or [])
        items.append({
            "id": m.get("id"),
            "version_id": v.get("id"),
            "name": m.get("name") or f"model-{m.get('id')}",
            "creator": creator,
            "description": (m.get("description") or "")[:600],
            "tags": list(m.get("tags") or []),
            "downloads": (m.get("stats") or {}).get("downloadCount"),
            "rating": (m.get("stats") or {}).get("rating"),
            "nsfw": bool(m.get("nsfw")),
            "preview_url": preview,
            "preview_type": preview_type,        # "image" | "video" | None
            "filename": primary.get("name"),
            "size_kb": primary.get("sizeKB"),
            "download_url": primary.get("downloadUrl"),
            "trigger_words": trigger,
            "recommended_strength": 1.0,    # CivitAI doesn't expose this; default
            "base_model": v.get("baseModel"),
            "civitai_url": f"https://civitai.com/models/{m.get('id')}",
        })
    # Defense-in-depth: when Spicy mode is off, also drop any items the
    # API returned with nsfw=true. CivitAI's `nsfw=false` request param
    # filters by image-tier (Soft/Mature/X) but model cards have a
    # separate boolean we re-check here so nothing slips through.
    if not spicy_on:
        items = [it for it in items if not it.get("nsfw")]
    metadata = raw.get("metadata") or {}
    return {
        "items": items,
        "next_cursor": metadata.get("nextCursor"),
        "has_more": bool(metadata.get("nextCursor")),
    }


def _civitai_download(download_url: str, meta: dict) -> dict:
    """Download a CivitAI .safetensors into mlx_models/loras/ and write
    a sidecar JSON. Returns { name, path, sidecar_path, size_bytes }.
    Streams to a .partial file then renames atomically — a Pinokio kill
    mid-download leaves nothing the next scan would mistake for a
    complete LoRA."""
    import urllib.parse, urllib.request
    if not download_url:
        raise RuntimeError("download_url required")
    # Restrict to civitai.com to prevent the endpoint being used as a
    # generic HTTP fetcher. Subdomains (e.g. images.civitai.com) are
    # also OK because CivitAI sometimes redirects there.
    parsed = urllib.parse.urlparse(download_url)
    if parsed.scheme != "https" or not parsed.netloc.endswith("civitai.com"):
        raise RuntimeError(f"refusing to download from {parsed.netloc}; "
                           f"only civitai.com is allowed")
    # CivitAI's download endpoint started requiring auth for many models
    # in 2025+. The Authorization header sometimes works, but the
    # canonical path is `?token=<key>` on the URL — and many CDN hops
    # only honour the token in the URL. Try the URL form first when a
    # key is available.
    api_key_env = _active_civitai_key()
    if api_key_env and "token=" not in (parsed.query or ""):
        sep = "&" if parsed.query else "?"
        download_url = download_url + sep + "token=" + urllib.parse.quote(api_key_env)
    loras_dir = _safe_loras_dir()
    # Filename from meta (preferred — preserves CivitAI's name) or fall
    # back to the URL's last path segment.
    fname = (meta.get("filename") or
             os.path.basename(parsed.path) or
             f"civitai_{meta.get('id', 'unknown')}.safetensors")
    if not fname.lower().endswith(".safetensors"):
        fname += ".safetensors"
    # Sanitize aggressively — CivitAI names can contain spaces and
    # weirder characters; the helper later passes this filename through
    # the safetensors loader which is filesystem-only and fine with
    # spaces, but the picker UI is calmer with snake_case.
    safe_fname = re.sub(r"[^A-Za-z0-9._-]+", "_", fname).strip("_")
    target = loras_dir / safe_fname
    if target.exists():
        # Don't silently re-download. Surface the conflict so the user
        # can decide (the UI will offer a choice; for now just skip).
        return {
            "name": meta.get("name") or target.stem,
            "path": str(target),
            "size_bytes": target.stat().st_size,
            "skipped": True,
            "reason": "already exists",
        }
    tmp = target.with_suffix(target.suffix + ".partial")
    push(f"[civitai] downloading {meta.get('name') or safe_fname}")
    api_key = _active_civitai_key()
    headers = {"User-Agent": CIVITAI_USER_AGENT}
    if api_key:
        headers["Authorization"] = f"Bearer {api_key}"
    req = urllib.request.Request(download_url, headers=headers)
    bytes_written = 0
    last_log = 0.0
    try:
        try:
            resp_ctx = urllib.request.urlopen(req, timeout=60)
        except urllib.request.HTTPError as he:
            # Surface the 401 case with a clear remediation. CivitAI now
            # requires API tokens for most LoRA downloads, even SFW ones,
            # but the API key for the search endpoint is optional — so a
            # user can browse without setting up auth and only hit this
            # wall on first install.
            if he.code == 401:
                raise RuntimeError(
                    "CivitAI returned 401 Unauthorized. CivitAI requires an "
                    "API token for LoRA downloads. Get one at "
                    "https://civitai.com/user/account, then set the "
                    "CIVITAI_API_KEY environment variable before launching "
                    "the panel (or in Pinokio's Phosphene start script). "
                    "Restart Pinokio's Phosphene to pick it up."
                )
            raise
        with resp_ctx as resp:
            total = int(resp.headers.get("Content-Length") or 0)
            with tmp.open("wb") as fh:
                while True:
                    chunk = resp.read(1024 * 256)
                    if not chunk:
                        break
                    fh.write(chunk)
                    bytes_written += len(chunk)
                    now = time.time()
                    if now - last_log > 1.0:
                        if total:
                            pct = int(100 * bytes_written / total)
                            push(f"[civitai] {pct}% · "
                                 f"{bytes_written // (1024*1024)}/"
                                 f"{total // (1024*1024)} MB")
                        else:
                            push(f"[civitai] {bytes_written // (1024*1024)} MB")
                        last_log = now
        os.replace(tmp, target)
    except Exception:
        try: tmp.unlink()
        except OSError: pass
        raise
    push(f"[civitai] saved {target.name} ({bytes_written // (1024*1024)} MB)")
    # Write the sidecar — kept tolerant of meta gaps so a partial
    # payload still produces a usable picker entry.
    sidecar = target.with_suffix(".json")
    sidecar_data = {
        "name": meta.get("name") or target.stem,
        "description": meta.get("description") or "",
        "trigger_words": list(meta.get("trigger_words") or []),
        "recommended_strength": float(meta.get("recommended_strength") or 1.0),
        "preview_url": meta.get("preview_url"),
        "base_model": meta.get("base_model") or "LTXV 2.3",
        "civitai_id": meta.get("id"),
        "civitai_version_id": meta.get("version_id"),
        "civitai_url": meta.get("civitai_url"),
        "downloaded_at": iso_now(),
        "downloaded_size_bytes": bytes_written,
    }
    try:
        atomic_write_text(sidecar, json.dumps(sidecar_data, indent=2))
    except Exception as exc:
        push(f"[civitai] WARN: could not write sidecar ({exc})")
    return {
        "name": sidecar_data["name"],
        "path": str(target),
        "sidecar_path": str(sidecar),
        "size_bytes": bytes_written,
        "skipped": False,
    }


